function Doctors() {
  const [doctors, setDoctors] = useState([]);

  useEffect(() => {
    loadDoctors();
  }, []);

  const loadDoctors = async () => {
    try {
      const res = await API.get("/doctors");
      setDoctors(res.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div className="container mt-5">

      <h2 className="mb-4">
        Available Doctors
      </h2>

      <div className="row">

        {doctors.map((doctor) => (
          <div
            className="col-md-4 mb-4"
            key={doctor._id}
          >
            <div className="card shadow h-100">

              <div className="card-body">

                <h4>
                  {doctor.doctorName}
                </h4>

                <p>
                  {doctor.specialization}
                </p>

                <p>
                  Experience:
                  {" "}
                  {doctor.experience}
                  {" "}
                  Years
                </p>

                <button
                  className="btn btn-primary w-100"
                >
                  Book Appointment
                </button>

              </div>

            </div>
          </div>
        ))}

      </div>

    </div>
  );
}

export default Doctors;
